const items = $input.all();

// Step 1: Group rows by NUMBER
const groups = {};
const order = []; // to preserve ticket order

for (const item of items) {
  const row = item.json;
  const num = row.NUMBER;

  if (!groups[num]) {
    groups[num] = [];
    order.push(num);
  }
  groups[num].push(row);
}

// Step 2: For each group, sort comments by COMMENT_CREATED_ON asc, then merge
return order.map(num => {
  const rows = groups[num];

  // Sort by COMMENT_CREATED_ON ascending
  rows.sort((a, b) => {
    const dateA = a.COMMENT_CREATED_ON ? new Date(a.COMMENT_CREATED_ON) : new Date(0);
    const dateB = b.COMMENT_CREATED_ON ? new Date(b.COMMENT_CREATED_ON) : new Date(0);
    return dateA - dateB;
  });

  // Take base fields from the first row
  const base = { ...rows[0] };

  // Merge comments in sorted order
  base.COMMENT_TEXT = rows
    .map(r => {
      const author = r.COMMENT_CREATED_BY || 'Unknown';
      const date = r.COMMENT_CREATED_ON || '';
      const text = r.COMMENT_TEXT || '';
      return `[${date}] ${author}: ${text}`;
    })
    .filter(c => c.trim() !== '[] :') // drop empty comments
    .join('\n---\n');

  return { json: base };
});

const row = $input.item.json;

const prompt = `You are an expert support ticket analyst. Analyze the following service request and return a structured JSON response.

## Service Request Data

**Ticket Number:** ${row.NUMBER || ''}
**Summary:** ${row.SUMMARY || ''}
**Industry:** ${row.INDUSTRY || ''}
**Description:** ${row.DESCRIPTION || ''}
**Request Type:** ${row.U_REQUEST_TYPE || ''}
**Customer Tier:** ${row.U_CUSTOMER_TIER || ''}
**Customer Type:** ${row.U_CUSTOMER_TYPE || ''}
**Customer Segment:** ${row.U_CUSTOMER_SEGMENT || ''}

**Comments (chronological):**
${row.COMMENT_TEXT || 'No comments available'}

---

## Instructions

Analyze ONLY the qualitative content above (summary, description, comments). Do NOT use any pre-existing categorization fields as input for your judgment.

Return a JSON object with exactly these fields:

{
  "overall_summary": "A concise 4-5 sentence narrative covering: what the customer reported, what was investigated, what the root cause was, and how it was or is being resolved. Should read like a ticket handoff note.",
  "customer_request_summary": "2-3 sentence plain English summary of what the customer is asking for or experiencing",
  "root_cause_summary": "2-3 sentence summary of the root cause or reason behind this ticket",
  "customer_trigger": one of exactly: [
    "General enquiry",
    "Feature not working",
    "Failures showing up in analytics",
    "Custom requirement",
    "Data issue",
    "Others"
  ],
  "sentiment": one of exactly: ["Positive", "Neutral", "Negative", "Frustrated", "Escalating"],
  "product": one of exactly: ["Job pull", "HSI", "HSI 2way", "Employee pull", "Other integrations"] job sync and job pull are same,
  "root_cause_category": one of exactly: [
    "config issue(only if phenon settings are wrong during setup)",
    "config updates(customer asked to update the existing config)"
    "request for historical pull",
    "platform issue IX",
    "ATS issues(ATS did not send the data, or something wrong at ATS end)",
    "category mapping",
    "platform issue downstream(integrationw as successful but error at consumption by downstream)",
    "job pull delete threshold",
    "knowledge gap(customer do not understand this is how it should function)",
    "customer enquiry",
    "others"
  ]
}

Rules:
- Return ONLY the raw JSON object. No markdown, no code fences, no explanation.
- If you cannot confidently determine the product or category, use "Other integrations" or "others" respectively.
- For sentiment, judge based on the customer's tone and language across the comments thread — not the resolution outcome.
- For customer_trigger, identify what initially prompted the customer to raise this ticket.
- Base your judgment purely on the text content provided above.`;

return {
  json: {
    ...row,
    _prompt: prompt
  }
};

const item = $input.item.json;

// Reach back to original ticket data from the Build Prompt node
const originalRow = $('Create prompt').item.json;
const { _prompt, ...cleanOriginal } = originalRow;

// Strict null-safe error check
const hasError = item.error != null
  && typeof item.error === 'object'
  && (item.error.message || item.error.code || item.error.status);

if (hasError) {
  const errorMessage = item.error?.message?.toLowerCase() || '';
  const errorCode = item.error?.code || item.error?.status;

  const isRateLimit = errorMessage.includes('rate limit') || errorCode === 429;
  const isTimeout = errorMessage.includes('timeout') || errorCode === 408;
  const isServerError = Number(errorCode) >= 500;

  let errorType = 'API_ERROR';
  if (isRateLimit) errorType = 'RATE_LIMIT_RETRY';
  if (isTimeout) errorType = 'TIMEOUT_RETRY';
  if (isServerError) errorType = 'SERVER_ERROR_RETRY';

  return {
    json: {
      ...cleanOriginal,
      _had_error: true,
      _error_type: errorType,
      _error_message: item.error?.message || 'Unknown error',
      _needs_retry: isRateLimit || isTimeout || isServerError,
      ai_overall_summary: errorType,
      ai_customer_request_summary: errorType,
      ai_root_cause_summary: errorType,
      ai_customer_trigger: 'Others',
      ai_sentiment: 'Neutral',
      ai_product: 'Other integrations',
      ai_root_cause_category: 'others',
      _parse_error: null
    }
  };
}

// No error — pass original ticket data + clean flags
return {
  json: {
    ...cleanOriginal,
    _had_error: false,
    _error_type: null,
    _error_message: null,
    _needs_retry: false,
    // Carry OpenAI output forward for parse node
    output: item.output
  }
};

const item = $input.item.json;

// Reach back to original ticket data from the Build Prompt node
const originalRow = $('Create prompt').item.json;
const { _prompt, ...cleanOriginal } = originalRow;

// If error handler already flagged an API error, skip parsing
if (item._had_error) {
  return {
    json: {
      ...cleanOriginal,
      ai_overall_summary: item.ai_overall_summary || item._error_type || 'API_ERROR',
      ai_customer_request_summary: item.ai_customer_request_summary || item._error_type || 'API_ERROR',
      ai_root_cause_summary: item.ai_root_cause_summary || item._error_type || 'API_ERROR',
      ai_customer_trigger: 'Others',
      ai_sentiment: 'Neutral',
      ai_product: 'Other integrations',
      ai_root_cause_category: 'others',
      _had_error: true,
      _error_type: item._error_type,
      _error_message: item._error_message,
      _needs_retry: item._needs_retry,
      _parse_error: null
    }
  };
}

// --- Extract raw text from n8n OpenAI node response ---
// Actual structure: item.output[0].content[0].text
let rawResponse = '';

if (Array.isArray(item.output)) {
  for (const block of item.output) {
    // Try direct block.text first
    if (block.text) {
      rawResponse = block.text;
      break;
    }
    // Try nested content array (n8n OpenAI node actual structure)
    if (Array.isArray(block.content)) {
      const contentBlock = block.content.find(c =>
        c.type === 'output_text' || c.type === 'text'
      );
      if (contentBlock?.text) {
        rawResponse = contentBlock.text;
        break;
      }
    }
  }
}

// Fallbacks for other possible response shapes
if (!rawResponse) rawResponse = item.message?.content || '';
if (!rawResponse) rawResponse = item.choices?.[0]?.message?.content || '';
if (!rawResponse) rawResponse = item.text || '';

// Unescape doubled quotes from n8n serialization (e.g. "" → ")
rawResponse = rawResponse.replace(/""/g, '"').trim();

// Strip markdown fences if present
rawResponse = rawResponse.replace(/```json|```/gi, '').trim();

// --- Handle empty response ---
if (!rawResponse) {
  return {
    json: {
      ...cleanOriginal,
      ai_overall_summary: 'EMPTY_RESPONSE',
      ai_customer_request_summary: 'EMPTY_RESPONSE',
      ai_root_cause_summary: 'EMPTY_RESPONSE',
      ai_customer_trigger: 'Others',
      ai_sentiment: 'Neutral',
      ai_product: 'Other integrations',
      ai_root_cause_category: 'others',
      _had_error: true,
      _error_type: 'EMPTY_RESPONSE',
      _error_message: 'OpenAI returned an empty response',
      _needs_retry: true,
      _parse_error: null
    }
  };
}

// --- Parse JSON ---
let analysis = {};
let parseError = null;

try {
  analysis = JSON.parse(rawResponse);
} catch (e) {
  parseError = rawResponse;
}

// --- Handle parse failure ---
if (parseError) {
  return {
    json: {
      ...cleanOriginal,
      ai_overall_summary: 'PARSE_ERROR',
      ai_customer_request_summary: 'PARSE_ERROR',
      ai_root_cause_summary: 'PARSE_ERROR',
      ai_customer_trigger: 'Others',
      ai_sentiment: 'Neutral',
      ai_product: 'Other integrations',
      ai_root_cause_category: 'others',
      _had_error: true,
      _error_type: 'PARSE_ERROR',
      _error_message: 'Could not parse JSON from OpenAI response',
      _needs_retry: true,
      _parse_error: rawResponse
    }
  };
}

// --- Validate categorical fields against allowed values ---
const validProducts = ['Job pull', 'HSI', 'HSI 2way', 'Employee pull', 'Other integrations'];
const validCategories = [
  'config issue',
  'request for historical pull',
  'platform issue IX',
  'ATS issues(ATS did not send the data)',
  'category mapping',
  'platform issue downstream',
  'job pull delete threshold',
  'knowledge gap(customer do not understand this is how it should function)',
  'customer enquiry',
  'others'
];
const validTriggers = [
  'General enquiry',
  'Feature not working',
  'Failures showing up in analytics',
  'Custom requirement',
  'Data issue',
  'Others'
];
const validSentiments = ['Positive', 'Neutral', 'Negative', 'Frustrated', 'Escalating'];

const product = validProducts.includes(analysis.product)
  ? analysis.product : 'Other integrations';
const rootCauseCategory = validCategories.includes(analysis.root_cause_category)
  ? analysis.root_cause_category : 'others';
const customerTrigger = validTriggers.includes(analysis.customer_trigger)
  ? analysis.customer_trigger : 'Others';
const sentiment = validSentiments.includes(analysis.sentiment)
  ? analysis.sentiment : 'Neutral';

// --- Merge AI output into original ticket row ---
return {
  json: {
    ...cleanOriginal,
    ai_overall_summary: analysis.overall_summary || '',
    ai_customer_request_summary: analysis.customer_request_summary || '',
    ai_root_cause_summary: analysis.root_cause_summary || '',
    ai_customer_trigger: customerTrigger,
    ai_sentiment: sentiment,
    ai_product: product,
    ai_root_cause_category: rootCauseCategory,
    _had_error: false,
    _error_type: null,
    _error_message: null,
    _needs_retry: false,
    _parse_error: null
  }
};
